#include<bits/stdc++.h>
using namespace std;
bool vis[101][101];
int f[101][101],a[101],len;
int dfs(bool limit,bool lead,int pos,int cha)
{
    if(pos==0)
    {
        return cha>=30;
    }
    if(!limit&&!lead&&vis[pos][cha])
    {
        return f[pos][cha];
    }
    int ans=0,up=(limit?a[pos]:1);
    for(int i=0;i<=up;i++)
    {
        ans+=dfs(limit&(i==a[pos]),lead&(i==0),pos-1,cha+(i==0?(lead?0:1):-1));
    }
    if(!limit&&!lead)
    {
        vis[pos][cha]=1;
        f[pos][cha]=ans;
    }
    return ans;
}
int solve(int x)
{
    len=0;
    while(x)
    {
        a[++len]=x%2;
        x/=2;
    }
    return dfs(1,1,len,30);
}
int main()
{
    int l,r;
    scanf("%d%d",&l,&r);
    printf("%d\n",solve(r)-solve(l-1));
    return 0;
}
